framework_css:
:root {
  --color-primary-500: #0052CC;
  --color-primary-600: #0046A8;
  --color-secondary-500: #1A73E8;
  --color-accent-500: #0052CC;
  --color-neutral-0: #FFFFFF;
  --color-neutral-50: #F7F7F7;
  --color-neutral-200: #DDDDDD;
  --color-neutral-500: #777777;
  --color-neutral-800: #333333;
  --color-success: #22A65F;
  --color-error: #D93025;
  --color-warning: #F6A623;
  --color-info: #2F80ED;

  --font-family-base: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-size-xs: 12px;
  --font-size-sm: 14px;
  --font-size-md: 16px;
  --font-size-lg: 20px;
  --font-size-xl: 24px;

  --line-height-tight: 1.25;
  --line-height-base: 1.5;

  --radius-sm: 4px;
  --radius-md: 6px;
  --radius-pill: 999px;

  --shadow-soft: 0 0 0 1px rgba(0, 0, 0, 0.03);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-family-base);
  font-size: var(--font-size-md);
  line-height: var(--line-height-base);
  color: var(--color-neutral-800);
  background-color: var(--color-neutral-50);
}

img {
  max-width: 100%;
  height: auto;
}

a {
  color: var(--color-primary-500);
  text-decoration: none;
  transition: color 0.15s ease;
}

a:hover,
a:focus-visible {
  color: var(--color-primary-600);
}

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* HEADER */

.site-header {
  background-color: var(--color-neutral-0);
  border-bottom: 1px solid var(--color-neutral-200);
}

.header-inner {
  max-width: 1040px;
  margin: 0 auto;
  padding: 12px 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  color: var(--color-neutral-800);
  font-weight: 600;
  letter-spacing: 0.02em;
}

.brand:hover,
.brand:focus-visible {
  color: var(--color-neutral-800);
}

.brand-logo {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 20%, #FFFFFF 0, #FFFFFF 35%, #8B3A24 36%, #5B2515 65%, #3A170E 100%);
  box-shadow: 0 0 0 2px var(--color-neutral-0), 0 0 0 3px var(--color-neutral-200);
}

.brand-name {
  font-size: 18px;
}

.main-nav ul {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  align-items: center;
  gap: 12px;
}

.main-nav a {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 14px;
  border-radius: var(--radius-pill);
  font-size: var(--font-size-sm);
  color: var(--color-neutral-800);
  border: 1px solid transparent;
  transition: background-color 0.15s ease, color 0.15s ease, border-color 0.15s ease, box-shadow 0.15s ease;
}

.main-nav a:hover,
.main-nav a:focus-visible {
  background-color: var(--color-neutral-0);
  border-color: var(--color-primary-500);
  color: var(--color-primary-500);
  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.02);
}

.main-nav a.is-active {
  background-color: var(--color-primary-500);
  color: var(--color-neutral-0);
  border-color: var(--color-primary-500);
}

/* MAIN CONTENT SHELL */

.page-content {
  min-height: calc(100vh - 72px - 140px);
  padding: 40px 24px 64px;
}

.page-content > * {
  max-width: 480px;
  margin-left: auto;
  margin-right: auto;
}

/* FOOTER */

.site-footer {
  background-color: var(--color-neutral-0);
  border-top: 1px solid var(--color-neutral-200);
}

.footer-inner {
  max-width: 1040px;
  margin: 0 auto;
  padding: 24px;
}

.footer-links {
  display: flex;
  flex-wrap: wrap;
  gap: 32px;
  margin-bottom: 16px;
}

.footer-column {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.site-footer a {
  font-size: var(--font-size-sm);
  color: var(--color-neutral-500);
}

.site-footer a:hover,
.site-footer a:focus-visible {
  color: var(--color-primary-500);
}

.footer-meta {
  border-top: 1px solid var(--color-neutral-200);
  padding-top: 12px;
  text-align: center;
}

.footer-copy {
  font-size: var(--font-size-xs);
  color: var(--color-neutral-500);
}

/* RESPONSIVE ADJUSTMENTS */

@media (max-width: 768px) {
  .header-inner {
    flex-direction: column;
    align-items: stretch;
    gap: 10px;
  }

  .brand {
    justify-content: center;
  }

  .main-nav ul {
    flex-wrap: wrap;
    justify-content: center;
  }

  .page-content {
    padding: 32px 16px 48px;
  }

  .footer-inner {
    padding: 20px 16px;
  }

  .footer-links {
    gap: 16px 32px;
  }
}
